firmware_template.source:
#include "led_output.h"
#include <Arduino.h>
#define LED_PIN 2
static bool _on = false;
static unsigned long _blinkLast = 0;
static uint16_t _blinkOn = 0, _blinkOff = 0;
void led_setup() {
  ledcAttach(LED_PIN, 5000, 8);
  Serial.println("[led] OK pin=2");
}
void led_on() { ledcWrite(LED_PIN, 255); _on = true; }
void led_off() { ledcWrite(LED_PIN, 0); _on = false; }
void led_set_brightness(uint8_t b) { ledcWrite(LED_PIN, b); _on = (b > 0); }
void led_blink(uint16_t on_ms, uint16_t off_ms) { _blinkOn = on_ms; _blinkOff = off_ms; }
